import { readFileSync } from "node:fs";
import path from "node:path";
import Link from "next/link";
import { notFound } from "next/navigation";
import { resolveScope, reportKeyToCampaign } from "@/lib/scope";
import { REPORTS } from "../reports";

export const metadata = {
  title: "Coverage — EHC Admin",
  robots: { index: false, follow: false },
};

// A single campaign's coverage report, served behind the admin session gate
// (the AdminShell + proxy.ts) and rendered in an iframe. The report HTML is
// generated by the Python pipeline and committed under content/coverage/.
// Nav chrome comes from the shell; this page adds only a Report/Summary toggle.

function loadReport(file: string): string | null {
  try {
    return readFileSync(
      path.join(process.cwd(), "content", "coverage", file),
      "utf8",
    );
  } catch {
    return null;
  }
}

export default async function CoveragePage({
  params,
  searchParams,
}: {
  params: Promise<{ campaign: string }>;
  searchParams: Promise<{ view?: string }>;
}) {
  const { campaign } = await params;
  const { view } = await searchParams;

  const report = REPORTS[campaign];
  if (!report) notFound();

  // Permission gate: reports contain outlet data, so only a superadmin or a
  // member of the report's org may view it — independent of the current
  // switcher selection (which is a view filter, not a permission boundary).
  const { scope, projects, user } = await resolveScope();
  const campaignSlug = reportKeyToCampaign(campaign);
  const allowed =
    user.role === "superadmin" ||
    projects.some((p) => p.campaignSlug === campaignSlug);
  if (!allowed) notFound();
  void scope;

  const wantSummary = view === "summary" && report.summary;
  const file = wantSummary ? report.summary! : report.file;
  const html = loadReport(file);

  return (
    <div>
      <div
        style={{
          display: "flex",
          alignItems: "baseline",
          gap: 18,
          marginBottom: 14,
        }}
      >
        <h1 style={{ fontSize: 20, fontWeight: 600, margin: 0 }}>
          {report.label} coverage
        </h1>
        <Link
          href={`/admin/coverage/${campaign}`}
          style={{ fontSize: 13, color: wantSummary ? "#666" : "#111", fontWeight: wantSummary ? 400 : 700 }}
        >
          Report
        </Link>
        {report.summary ? (
          <Link
            href={`/admin/coverage/${campaign}?view=summary`}
            style={{ fontSize: 13, color: wantSummary ? "#111" : "#666", fontWeight: wantSummary ? 700 : 400 }}
          >
            Summary
          </Link>
        ) : null}
      </div>

      {html ? (
        <iframe
          title={`${report.label} coverage`}
          srcDoc={html}
          style={{
            width: "100%",
            height: "calc(100vh - 190px)",
            minHeight: 520,
            border: "1px solid #e3e1d8",
            borderRadius: 8,
            background: "#fff",
            display: "block",
          }}
        />
      ) : (
        <p style={{ color: "#666", fontSize: 14, maxWidth: "60ch" }}>
          The {report.label} report isn&apos;t on disk. Regenerate it in{" "}
          <code>~/ehc-press</code> and run{" "}
          <code>python3 tools/publish_coverage_to_ehc.py</code>, then commit{" "}
          <code>content/coverage/</code>.
        </p>
      )}
    </div>
  );
}
